cdef double Norm(double[:] vector1, double[:] vector2):
	cdef double res = 0
	cdef int i
	for i in range(3):
		res += (vector1[i]-vector2[i])**2
	res = res ** 0.5
	return res

cdef double[:] AccelerationTM(double[:] coordFirst, double[:] coordSecond,double mass):
