clause_counter = 0

cdef class Clause:

    def __init__(self, ls):
        global clause_counter
        self.id = clause_counter
        clause_counter += 1

        self.ls = [l for l in ls]
        self.singleton = len(self.ls) == 1
        # assume non-triviality
        self.trivial = False

    @classmethod
    def from_ns(cls, ns):
        """ns - a list of integers representing literals"""
        cdef:
            Clause c
            set ls
            bint trivial
            Literal l

        ls = set()
        trivial = False
        for n in ns:
            l = Literal(n)
            ls.add(l)
            # check if both n and -n are present
            if -l in ls:
                trivial = True

        c = cls(ls)
        c.trivial = trivial
        return c

    def resolve(self, Clause other, int on):
        cdef:
            set ls = set()
            Literal l
        for l in self.ls:
            if l.var != on:
                ls.add(l)
        for l in other.ls:
            if l.var != on:
                ls.add(l)
        return Clause(ls)

    def equiv(self, other):
        return len(self) == len(other) and all([l in other for l in self])


    cdef bint has_var(self, int x):
        cdef Literal l = Literal(x)
        return l in self.ls or -l in self.ls

    cdef list xs(self):
        cdef Literal l
        return [l.var for l in self.ls]

    cdef list start_watching(self):
        cdef:
            list res = list()
            Literal l
        for l in self.ls:
            res.append(l)
            if len(res) == 2:
                break
        assert(len(res) == 2)
        return res

    cdef Literal get_only(self):
        assert(len(self.ls) == 1)
        return self.ls[0]

    cdef int index(self, Literal l):
        return self.ls.index(l)

    def __len__(self):
        return len(self.ls)

    def __iter__(self):
        return iter(self.ls)

    def __eq__(self, other):
        return self.id == other.id

    def __lt__(self, other):
        return self.id < other.id

    def __hash__(self):
        return self.id

    def __getitem__(self, i):
        return self.ls[i]

    def __setitem__(self, i, l):
        self.ls[i] = l

    def modeled_by(self, m):
        """Determine if clause c can be modeled by m"""
        # m can always model clause c if c contains free vars not captured by m
        return any(l not in m or m[l] for l in self.ls)

    def modeled_by_modulo(self, m, v):
        """Determine if clause c could be modeled by m if variable v were absent"""
        return any(l not in m or m[l] for l in self.ls if l.var != v)

    def __str__(self):
        return repr(self)

    def __repr__(self):
        return repr(self.ls)


cdef class Literal:

    def __init__(self, n):
        self.n = n
        self.var = abs(n)
        self.is_pos = n > 0
        self.is_neg = n < 0

    cdef int sign(self):
        return 1 if self.is_pos else -1

    def __neg__(self):
        return Literal(-self.n)

    def __str__(self):
        return str(self.n)

    def __repr__(self):
        return str(self.n)

    def __eq__(self, Literal other):
        return self.n == other.n

    def __lt__(self, Literal other):
        return self.var < other.var and self.is_neg < other.is_neg

    def __hash__(self):
        return self.n

from collections import defaultdict
from smoke.model.dt.const import Flag


cpdef RecvTable mk(object dt, object recv_props):
    cdef object priorities
    cdef int offset = 0
    cdef int hole, cursor
    cdef object recv_prop
    cdef int flagged_changes_often, changes_often

    recv_props = list(recv_props) # copy
    priorities = sorted(set([rp.pri for rp in recv_props] + [64]))

    for priority in priorities:

        hole = cursor = offset

        while cursor < len(recv_props):
            recv_prop = recv_props[cursor]
            flagged_changes_often = recv_prop.flags & Flag.ChangesOften
            changes_often = flagged_changes_often and priority is 64

            if changes_often or recv_prop.pri == priority:
                recv_props[hole], recv_props[cursor] = \
                    recv_props[cursor], recv_props[hole]
                hole, offset = hole + 1, offset + 1

            cursor += 1

    return RecvTable(dt, recv_props)


cdef class RecvTable(object):
    def __init__(self, dt, recv_props):
        self.dt = dt
        self.recv_props = recv_props
        self._cache = dict()

    def __iter__(self):
        return iter(self.recv_props)

    def __init__(self, dt, recv_props):
        self.dt = dt
        self._recv_props = recv_props

        self._by_src = None
        self._by_name = None
        self._by_tuple = None

    def __iter__(self):
        return iter(self._recv_props)

    property by_index:
        def __get__(self):
            return self._recv_props

    property by_src:
        def __get__(self):
            if self._by_src is None:
                self._by_src = defaultdict(list)

                for i, recv_prop in enumerate(self):
                    self._by_src[recv_prop.src].append((i, recv_prop))

            return self._by_src

    property by_name:
        def __get__(self):
            if self._by_name is None:
                self._by_name = defaultdict(list)

                for i, recv_prop in enumerate(self):
                    self._by_name[recv_prop.name].append((i, recv_prop))

            return self._by_name

    property by_tuple:
        def __get__(self):
            if self._by_tuple is None:
                self._by_tuple = dict()

                for i, recv_prop in enumerate(self):
                    _tuple = (recv_prop.src, recv_prop.name)
                    self._by_tuple[_tuple] = (i, recv_prop)

            return self._by_tuple
